from functools import lru_cache
class Solution:
    def minOperations(self, word1, word2):
        def cost_brute(a, b):
            n = len(a)
            best = 10 ** 9
            idx = list(range(n))
            def matchings(rem):
                if not rem:
                    yield []
                    return
                first = rem[0]
                for m in matchings(rem[1:]):
                    yield m
                for kk in range(1, len(rem)):
                    rest = rem[1:kk] + rem[kk + 1:]
                    for m in matchings(rest):
                        yield [(first, rem[kk])] + m
            for rev in (0, 1):
                base = a[::-1] if rev else a
                for match in matchings(idx):
                    p = list(range(n))
                    for x, y in match:
                        p[x] = y
                        p[y] = x
                    rep = sum(1 for i in range(n) if base[p[i]] != b[i])
                    best = min(best, rev + len(match) + rep)
            return best
        @lru_cache(maxsize=None)
        def f(a, b):
            if not a:
                return 0
            return min(cost_brute(a[:i], b[:i]) + f(a[i:], b[i:]) for i in range(1, len(a) + 1))
        return f(word1, word2)

