from collections import Counter
class Solution:
    def minOperations(self, word1, word2):
        def cost(a, b):
            best = 10 ** 9
            m = len(a)
            for rev in (0, 1):
                base = a[::-1] if rev else a
                cnt = Counter()
                mis = 0
                for i in range(m):
                    if base[i] != b[i]:
                        mis += 1
                        cnt[(base[i], b[i])] += 1
                pairs = 0
                used = set()
                for (x, y), c in cnt.items():
                    if (x, y) in used or x == y:
                        continue
                    used.add((x, y))
                    used.add((y, x))
                    pairs += min(c, cnt.get((y, x), 0))
                v = rev + mis - pairs
                if v < best:
                    best = v
            return best
        n = len(word1)
        INF = 10 ** 9
        dp = [INF] * (n + 1)
        dp[0] = 0
        for i in range(1, n + 1):
            for j in range(i):
                c = dp[j] + cost(word1[j:i], word2[j:i])
                if c < dp[i]:
                    dp[i] = c
        return dp[n]

