var minOperations = function(word1, word2) {
    const cost = (a, b) => {
        let best = Infinity;
        const m = a.length;
        for (let rev = 0; rev < 2; rev++) {
            const base = rev ? a.split('').reverse().join('') : a;
            const cnt = new Map();
            let mis = 0;
            for (let i = 0; i < m; i++) {
                if (base[i] !== b[i]) {
                    mis++;
                    const key = base[i] + b[i];
                    cnt.set(key, (cnt.get(key) || 0) + 1);
                }
            }
            let pairs = 0;
            const used = new Set();
            for (const [key, c] of cnt.entries()) {
                const x = key[0], y = key[1];
                if (used.has(key) || x === y) continue;
                used.add(key);
                used.add(y + x);
                pairs += Math.min(c, cnt.get(y + x) || 0);
            }
            const v = rev + mis - pairs;
            if (v < best) best = v;
        }
        return best;
    };
    const n = word1.length;
    const dp = new Array(n + 1).fill(Infinity);
    dp[0] = 0;
    for (let i = 1; i <= n; i++) {
        for (let j = 0; j < i; j++) {
            const c = dp[j] + cost(word1.slice(j, i), word2.slice(j, i));
            if (c < dp[i]) dp[i] = c;
        }
    }
    return dp[n];
};
